<template>
  <div class="course-view">
    <el-button type="text" @click="goBack" class="back-btn">
      ← 返回
    </el-button>

    <div v-if="loading"><el-skeleton :rows="10" animated /></div>

    <div v-else-if="error">
      <el-result icon="error" title="加载失败" :sub-title="error" />
    </div>

    <template v-else-if="course">
      <el-card>
        <h2 class="course-title">{{ course.title }}</h2>
        <div class="course-meta">
          <el-tag size="mini" type="info">{{ contentTypeText }}</el-tag>
          <span class="course-time">{{ course.estimatedMinutes }} 分钟</span>
          <el-button v-if="!isCompleted" type="primary" size="small"
            :loading="completing" @click="handleComplete" class="complete-btn">
            标记完成
          </el-button>
          <el-tag v-else type="success" size="medium">✓ 已完成</el-tag>
        </div>
        <el-divider />
        <div class="course-content">
          <markdown-renderer :content="course.contentMarkdown || '暂无内容'" />
        </div>
      </el-card>
    </template>
  </div>
</template>

<script>
import MarkdownRenderer from '../components/MarkdownRenderer.vue';
import { learningPathApi } from '../api';
import { mockLearningPaths } from '../mock';

export default {
  name: 'CourseView',
  components: { MarkdownRenderer },
  data() {
    return {
      course: null,
      loading: true,
      error: '',
      completing: false,
      isCompleted: false
    };
  },
  created() { this.loadCourse(); },
  methods: {
    async loadCourse() {
      this.loading = true;
      const courseId = Number(this.$route.params.courseId);
      try {
        const res = await learningPathApi.getCourse(courseId);
        if (res.code === 200 && res.data) {
          this.course = res.data;
        } else {
          // fallback to mock data
          for (const path of mockLearningPaths) {
            if (path.courses) {
              const c = path.courses.find(co => co.id === courseId);
              if (c) { this.course = c; break; }
            }
          }
          if (!this.course) this.error = '课程未找到';
        }
      } catch {
        this.error = '网络请求失败';
      } finally {
        this.loading = false;
      }
    },
    goBack() {
      if (window.history.length > 1) this.$router.back();
      else this.$router.push('/learning-paths');
    },
    async handleComplete() {
      this.completing = true;
      try {
        const res = await learningPathApi.completeCourse({
          courseId: Number(this.$route.params.courseId),
          pathId: this.course.pathId || 0
        });
        if (res.code === 200) {
          this.isCompleted = true;
          this.$message.success('恭喜完成本课程！');
        }
      } finally {
        this.completing = false;
      }
    }
  },
  computed: {
    contentTypeText() {
      const map = { ARTICLE: '文章', VIDEO: '视频', CODING: '编程', QUIZ: '测验' };
      return map[this.course?.contentType] || this.course?.contentType || '';
    }
  }
};
</script>

<style scoped>
.back-btn { margin-bottom: 16px; }

.course-title { font-size: 24px; margin-bottom: 12px; }

.course-meta {
  display: flex;
  align-items: center;
  gap: 12px;
  color: var(--text-secondary);
  font-size: 14px;
}

.complete-btn { margin-left: auto; }

.course-content {
  font-size: 15px;
  line-height: 1.8;
  min-height: 300px;
}
</style>
