<template>
  <div class="markdown-body" v-html="rendered"></div>
</template>

<script>
// 简易 Markdown 渲染（后续可替换为 marked + highlight.js 集成）
export default {
  name: 'MarkdownRenderer',
  props: {
    content: { type: String, default: '' }
  },
  computed: {
    rendered() {
      if (!this.content) return '';
      let html = this.content;

      // 代码块 (```)
      html = html.replace(/```(\w*)\n?([\s\S]*?)```/g, (match, lang, code) => {
        const escaped = this.escapeHtml(code.trim());
        return `<pre class="code-block"><code class="lang-${lang}">${escaped}</code></pre>`;
      });

      // 行内代码 (`)
      html = html.replace(/`([^`]+)`/g, '<code class="inline-code">$1</code>');

      // 标题 (## / ###)
      html = html.replace(/### (.+)/g, '<h3>$1</h3>');
      html = html.replace(/## (.+)/g, '<h2>$1</h2>');

      // 加粗 **
      html = html.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');

      // 无序列表
      html = html.replace(/^- (.+)/gm, '<li>$1</li>');
      html = html.replace(/(<li>.*<\/li>\n?)+/g, '<ul>$&</ul>');

      // 有序列表
      html = html.replace(/^\d+\. (.+)/gm, '<li>$1</li>');

      // 链接
      html = html.replace(/\[(.+?)\]\((.+?)\)/g, '<a href="$2" target="_blank">$1</a>');

      // 段落（双换行分割）
      const paragraphs = html.split(/\n\n+/);
      html = paragraphs.map(p => {
        p = p.trim();
        if (!p) return '';
        if (p.startsWith('<h') || p.startsWith('<ul') || p.startsWith('<pre') || p.startsWith('<li')) return p;
        return `<p>${p}</p>`;
      }).join('\n');

      return html;
    }
  },
  methods: {
    escapeHtml(text) {
      const map = { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#039;' };
      return text.replace(/[&<>"']/g, c => map[c]);
    }
  }
};
</script>

